// Implementation A:
class ViewModelA : ViewModel() {
    private val _nav = MutableStateFlow<String?>(null)
    val nav: StateFlow<String?> = _nav.asStateFlow()

    fun goToDetail(id: String) {
        _nav.value = "detail/$id"
    }
}

// Implementation B:
class ViewModelB : ViewModel() {
    private val _nav = MutableSharedFlow<String>()
    val nav: SharedFlow<String> = _nav.asSharedFlow()

    fun goToDetail(id: String) {
        viewModelScope.launch { _nav.emit("detail/$id") }
    }
}

class ProfileActivity : AppCompatActivity() {
    private val disposables = CompositeDisposable()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        disposables.add(
            RxBus.observe<UserEvent>()
                .observeOn(AndroidSchedulers.mainThread())
                .subscribe { event ->
                    nameTextView.text = event.user.name
                }
        )
    }

    // Missing: override fun onDestroy() { disposables.clear() }
}

// OLD: EventBus approach
class OldFragment : Fragment() {
    override fun onStart() {
        super.onStart()
        EventBus.getDefault().register(this)
    }
    override fun onStop() {
        super.onStop()
        EventBus.getDefault().unregister(this)
    }
    @Subscribe(threadMode = ThreadMode.MAIN)
    fun onData(event: DataEvent) { updateUi(event) }
}

// NEW: SharedFlow approach
class NewFragment : Fragment() {
    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        viewLifecycleOwner.lifecycleScope.launch {
            viewLifecycleOwner.repeatOnLifecycle(Lifecycle.State.STARTED) {
                viewModel.dataEvents.collect { event -> updateUi(event) }
            }
        }
    }
}
